import React, { useState } from 'react';
import './Home.css';
import ShareModal from './ShareModal';
import ChatModal from './ChatModal';

const Home = () => {
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);
  const [isChatModalOpen, setIsChatModalOpen] = useState(false);

  return (
    <div className="home">
      <div className="container">
        <div className="hero-section">
          <h1 className="hero-title">
            Feeling stressed?<br />
            You're not alone
          </h1>
          <p className="hero-subtitle">
            Share your thoughts, connect with others, and find support.
          </p>
          <div className="hero-buttons">
            <button 
              className="btn-primary"
              onClick={() => setIsShareModalOpen(true)}
            >
              Share your feelings
            </button>
            <button 
              className="btn-secondary"
              onClick={() => setIsChatModalOpen(true)}
            >
              + Chat with someone
            </button>
          </div>
        </div>

        <div className="features">
          <div className="feature-card">
            <div className="feature-icon">✏️</div>
            <h3>Share Anonymously</h3>
            <p>Express yourself safely without revealing your identity.</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">👥</div>
            <h3>Talk with Peers</h3>
            <p>Connect with mentors with peer skills when you're going through.</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">💚</div>
            <h3>Relax & Heal</h3>
            <p>Listen to destressing music and explore self-care resources.</p>
          </div>
        </div>
      </div>

      {isShareModalOpen && (
        <ShareModal onClose={() => setIsShareModalOpen(false)} />
      )}
      
      {isChatModalOpen && (
        <ChatModal onClose={() => setIsChatModalOpen(false)} />
      )}
    </div>
  );
};

export default Home;
